var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"와! 여긴 사람도 물고기도 정말 많아!","JPN":"わあ！　ここって人もお魚もすごくたくさん！","ENG":"Wow! There are so many people and fish here!","TWN":"哇！這裡有好多人跟好多魚喔！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 시그마는 모처럼 온 소풍이라 신났나 보네.","JPN":"ふふっ、シグマちゃんは久しぶりの遠足にすごく舞い上がっているみたいね。","ENG":"Haha. Sigma seems excited about her outing today.","TWN":"呵呵，西格瑪難得可以出來放風，很開心吧？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"릴리도 수족관에 처음 놀러와 본다고 했지?","JPN":"リリーも水族館は初めてなんでしょ？","ENG":"It's your first time to the aquarium too, Lily?","TWN":"莉莉也是第一次來水族館玩吧？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"죄송하지만, 전 놀러 온 게 아닙니다.","JPN":"申し訳ありませんが、私は遊びにきたわけではありません。","ENG":"I am sorry, but I am not here for pleasure.","TWN":"抱歉，我不是來玩的。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"견문을 넓히고 오라는 주인님의 지시에 따라서 왔을 뿐이죠.","JPN":"見聞を広げてこいというご主人様の指示に従い、来たまでです。","ENG":"I am here because Master has ordered that I broaden my horizons.","TWN":"是主人要我出來增廣見聞，我才奉主人之命來的。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그래? 어떻게 하라고 했는데?","JPN":"そう？　何をしろって言ってた？","ENG":"Oh, yeah? Now what did he say, exactly?","TWN":"是嗎？他是怎麼說的？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"다양한 해양생물을 확인하고 스쿠버 다이버들의 공연도 관람하라고 하셨습니다.","JPN":"様々な海洋生物を確認し、スクーバダイバーたちの公演も鑑賞してこいと言われました。","ENG":"He told me to observe the various marine lifeforms and watch the scuba-diving performance.","TWN":"主人說要確認各樣海洋生物，還要欣賞潛水秀。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"덧붙여서 방문을 인증할 수 있는 기념품도 꼭 챙겨 오라고 하셨죠.","JPN":"加えて、訪問を証明できる記念品もしっかり持って帰ってくるようにとおっしゃっていました。","ENG":"Also, to bring a souvenir as evidence of my visit.","TWN":"另外還要買紀念品，證明有來過。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그게 잘 놀고 오라는 뜻이야.","JPN":"それって楽しく遊んできなさいという意味なのよ。","ENG":"That means go have fun.","TWN":"這就是要你好好玩的意思。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……저에게는 따님을 보필해야 할 의무가 있어요.","JPN":"……私にはお嬢様を見守る義務があります。","ENG":"...But I have a duty to care for Sigma.","TWN":"……我有義務要保護好小姐。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이런 구경거리에 혹해서야 주인님의 메이드로서 실격이에요.","JPN":"こんな見せ物に魅了されているようでは、ご主人様のメイドとして失格です。","ENG":"If I am tempted by these kinds of spectacles, I will be unqualified to be Master's maid.","TWN":"要是因為玩樂而不務正業，那我就是個失職的女僕。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"릴리! 빨리 와서 이것 좀 봐!","JPN":"リリー！　早くこっちに来て、これを見てみてよ！","ENG":"Lily! Come here quick and look at this!","TWN":"莉莉快來！你看這個！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네, 따님. 금방 가겠습니다.","JPN":"はい、お嬢様。すぐに。","ENG":"Yes, Sigma. I will be right there.","TWN":"是，小姐，我馬上過去。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"먼저 실례하죠. 알렉스 님도 저에게 어쩔티비 저쩔티비 하지 마시고 구경하시면 됩니다.","JPN":"お先に失礼します。アレックス様も私にウザッたくなさらずに鑑賞を楽しめばいいのです。","ENG":"Excuse me. You should stop telling me about FOMO and come watch with us, Alex.","TWN":"失禮了。請雅蕾克絲小姐也不要再跟我五四三，你就玩你的吧。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"흐음…… 요즘 아이들 말투는 알아듣기가 참 어렵네.","JPN":"はぁ……最近の子の話し方ってわかりづらいわね。","ENG":"Hmm... It's hard to understand what kids are saying these days.","TWN":"嗯……最近的孩子講話真難懂。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"쟤는 <color=#ffd34c>피라냐</color>, 저기 저 큰 건 <color=#ffd34c>피라루쿠</color>야. 모두 아마존에서 발견할 수 있지.","JPN":"あれは<color=#ffd34c>ピラニア</color>、あそこの大きいのは<color=#ffd34c>ピラルクー</color>だよ。どっちもアマゾンで見られるの。","ENG":"That one's a <color=#ffd34c>piranha</color>, and that big one is called a <color=#ffd34c>pirarucu</color>. They can all be found in the Amazon.","TWN":"牠是<color=#ffd34c>食人魚</color>，, 很大的那條是<color=#ffd34c>象魚</color>，牠們都是在亞馬遜河中發現的喔。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! 나 쟤도 누군지 알아!","JPN":"あっ！　あれも知っているお魚！","ENG":"Oh! I know what that one is too!","TWN":"喔！牠我好像也知道！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이름은 <color=#ffd34c>흑가오리</color>고 <color=#ffd34c>매가오리목 색가오리과</color>의 가오리야!","JPN":"名前は<color=#ffd34c>ホシエイ</color>で、<color=#ffd34c>トビエイ目アカエイ科</color>に属するエイなんだ！","ENG":"It's called a <color=#ffd34c>pitted stingray</color> and it's part of the <color=#ffd34c>Dasyatidae family</color>!","TWN":"牠叫<color=#ffd34c>松原魟</color>，屬於<color=#ffd34c>鱝目，魟科</color>！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"길이가 2미터나 돼서 사람을 한 번에 덮을 수 있어. 이불처럼 말이야.","JPN":"長さが2メートルもあって、人を覆えるほどなんだよ。お布団みたいにね。","ENG":"Its disc is 2 meters wide and can even cover people. Like a blanket.","TWN":"長約2公尺，可以把整個人都蓋住，像棉被一樣。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"2미터……. 이불처럼 덮을 수도 있다…….","JPN":"2メートル……布団のように覆えるっと……","ENG":"2 meters... Can be used as a cover like a blanket...","TWN":"2公尺……像棉被一樣……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"다시 말해, 이불로 사용해도 된다는 말씀이신가요?","JPN":"要するに、布団として使用できるということなのでしょうか？","ENG":"So, in other words, it can be used as a blanket?","TWN":"也就是說，可以拿來當作棉被使用的意思嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"진짜로 덮으려면 조심해야 할 거야. 꼬리에 무시무시한 독침이 달려 있거든.","JPN":"本当に布団のように被ろうとするなら気をつけなくちゃだめだよ。尻尾に大きな毒針がついてるから。","ENG":"But you should be careful if you're really gonna use it. They have scary venomous stingers on their tails.","TWN":"真的要拿來蓋的話要小心，因為牠的尾巴上有毒針。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그건 까비네요. 주인님의 침실에 들여 놓긴 너무 위험하겠어요.","JPN":"ぴえん。ご主人様の寝室に入れるには危険すぎるようです。","ENG":"That's savage. It seems too dangerous to place one in Master's bedroom.","TWN":"真假，那不行，放在主人的臥室太危險了。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗, 주인님에게 선물을 주고 싶어?","JPN":"ふふっ、ご主人様にプレゼントしたいの？","ENG":"Haha, do you want to give your master a gift?","TWN":"呵呵，你想送主人禮物嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이, 이건 수면 담당으로서 당연히 신경써야 할 일이에요.","JPN":"こ、これは睡眠担当として気を遣って当たり前のところですから。","ENG":"A-as the one in charge of his sleep, it is my duty to care about stuff like this.","TWN":"那個，我負責主人的睡眠，當然要注意。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그러니? 정말로?","JPN":"そう？　本当に？","ENG":"Oh? Really?","TWN":"所以呢？真的嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"바, 방금 그렇다고 하지 않았나요?","JPN":"い、今そうだと言いましたよね！","ENG":"I-I just said so.","TWN":"我，我剛不是說了？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"알렉스 언니! 저기 수족관 안에 보물 상자가 있어!","JPN":"アレックスお姉ちゃん！　あそこの水槽の中に宝箱があるよ！","ENG":"Alex! There's a treasure chest inside the aquarium!","TWN":"雅蕾克絲姊姊！水族箱裡面有藏寶箱欸！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그래? 우리 시그마가 보물 상자를 발견했구나?","JPN":"あら？　シグマちゃんたら宝箱を見つけたのね？","ENG":"Oh? Did our Sigma discover a treasure chest?","TWN":"真的嗎？西格瑪發現藏寶箱啦？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! ","JPN":"あっ！ ","ENG":"Oh!","TWN":"哎呀！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그런데 흑가오리가 지키고 있어! 저러면 보물상자를 가져올 수가 없는데?","JPN":"でもホシアイがそれを守っている！　あれじゃ宝箱に手が出せないな。","ENG":"But that pitted stingray is guarding it! I don't think I'll be able to have it.","TWN":"可是有松原魟在看守著！那我就沒辦法拿到藏寶箱咧？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"응? 보물 상자를 가져오려고?","JPN":"うん？　宝箱を持ってくるつもり？","ENG":"Hmm? You want to take it home with you?","TWN":"嗯？你要把藏寶箱拿過來嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"당연하지! 훌륭한 해적이라면 보물 상자 하나쯤은 가지고 있어야 하는걸!","JPN":"もちろん！　立派な海賊なら宝箱の一つぐらい持っていなくちゃ！","ENG":"Of course! A great pirate should have at least one treasure chest!","TWN":"當然囉！偉大的海盜起碼都要有一個藏寶箱吧！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으으으으음……! 어쩌지……?","JPN":"ううううん……！　どうしよう……？","ENG":"Nnnngh...! What should I do...?","TWN":"呃呃呃……！怎麼辦呢……？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"시그마는 아까부터 수족관에서 눈을 못 떼네.","JPN":"シグマちゃんはさっきから水槽に釘付け状態ね。","ENG":"Sigma can't seem to take her eyes off of the aquarium.","TWN":"西格瑪從剛才就一直盯著水族箱。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"저렇게 붙어 있으면 벽에 얼굴 자국 남겠어.","JPN":"あんなにへばりついていると、ガラスに顔の跡がつきそうだわ。","ENG":"I think she's going to leave a face print on the glass at this rate.","TWN":"再這樣下去，她整個臉都要印在玻璃牆上了。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"왜? 나한테 할말 있니?","JPN":"何？　私に言いたいことでもあるの？","ENG":"What? Do you have something to say to me?","TWN":"怎麼了？你有話要跟我說嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"과몰입하지 마세요. 그런 것 없습니다.","JPN":"深読みしないでください。そんなんじゃありません。","ENG":"This ain't it, chief. Nothing.","TWN":"想太多，我才沒有。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"묻고 싶은 게 잔뜩 있다는 표정인데?","JPN":"聞きたいことがたくさんあるという顔をしているわよ？","ENG":"You're looking at me like you have a lot of questions.","TWN":"你一臉就是有很多問題要問的樣子欸？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"생면부지인 사람에게 그런 시선을 받는 이유가 궁금해지네. 얘기해 봐.","JPN":"初対面の私にそんな視線を送ってくる理由が気になるわ。話してみて。","ENG":"I'm wondering why you're looking at me, a total stranger, like that. Go ahead, shoot.","TWN":"我跟你也不熟，我想知道你為何用那種眼神看我，說吧。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……대답할 의무는 없습니다만, 그렇게 듣고 싶어하시면 어쩔 수 없죠.","JPN":"……答える義務はありませんが、そんなに聞きたいというなら仕方ありません。","ENG":"...I have no obligation to answer, but... if you really wish to know, so be it.","TWN":"……我沒義務回答你，但你這麼想知道的話，我就勉為其難跟你說吧。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"오늘 외출을 나서기 전에 주인님께서 저를 따로 부르셨습니다.","JPN":"今日、外出前にご主人様が個別に私をお呼びになりました。","ENG":"Master called me before we went out.","TWN":"今天外出前，主人另外把我找過去。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"따님의 안전을 위해 메이드장 님도 동행하셔야 한다고 말씀드렸더니, 당신이 있으면 괜찮으시다더군요.","JPN":"お嬢様の安全のためにはメイド長も同行すべきだと申し上げましたが、あなたがいれば大丈夫とおっしゃるんです。","ENG":"I told him that Chief Maid should also accompany us for his daughter Sigma's safety, and he said that you would be enough.","TWN":"我跟主人說，為了確保小姐的安全，必須請女僕長一起同行。主人卻說，有你在就夠了。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어떤 근거로 따님의 안전을 믿고 맡기시는 건지는 답해 주시지 않았고 말이죠.","JPN":"何を根拠にお嬢様の安全を信じ、任せるのかは答えていただけませんでした。","ENG":"But he did not give me any grounds for why he trusted you with his daughter.","TWN":"但主人沒說他是基於什麼原因，願意把女兒的人身安全交給你負責。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"주인님께는 늘 차분하고 어른스러우면서……","JPN":"ご主人様には、常に落ち着いていて、大人で……","ENG":"Master has this person who is always calm and mature...","TWN":"主人的處事風格一直以來都相當成穩……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어떤 일이든 능숙하게 처리할 줄 알고, 겸손한 데다가 다정하기까지 한 분이 계세요.","JPN":"何事もテキパキとやりこなすことができて、謙遜で、なおかつ暖かい方がそばにいらっしゃいます。","ENG":"and is capable of handling any situation. She is even modest and affectionate.","TWN":"明明就有一個辦事俐落、謙卑有禮的人在，"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 분은 꾸며내지 않은 아름다움과 강인함도 겸비하고 계시죠.","JPN":"その方は飾り気のない美しさと強さも兼ね備えています。","ENG":"She also possesses unaltered beauty and strength.","TWN":"而且還同時內外兼備。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런데 주인님께서 왜 그 분을 놔두시고……","JPN":"なのにどうしてご主人様は、その方ではなく……","ENG":"But why did Master dismiss her...","TWN":"但主人為何放著那樣的人不用……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"굳이 알렉스 님처럼 출신도, 성분도 불분명한 사람에게 일을 맡기셨는지 의문스러웠어요.","JPN":"アレックス様のような、出身も素性も不明瞭な人間に仕事を任せたのか疑問に思っていました。","ENG":"and instead pick someone with an unclear origin and composition like you, Ms. Alex?","TWN":"而是非要使用像你這種來歷不明的人，所以我感到很疑惑。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"제가 모르는 장점이 있는지 관찰해 봤지만, 아직은 노답이네요.","JPN":"私の知らない長所があるのかと観察してみましたが、なぁぜなぁぜって感じです。","ENG":"I've observed to see if I overlooked a strength that you had, but you aren't really giving.","TWN":"或許你有我不知道的優點，所以我也有嘗試觀察你，但可能我眼睛業障重，還沒看到。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"흐음…… 그래, 사장님이 그렇게 말했구나.","JPN":"ふうん……なるほど、社長はそう言ったと。","ENG":"Hmm... Okay. So that's what Boss said to you.","TWN":"呵呵……是嗎？老闆是這樣說的嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 나름대로 쓸모를 인정받은 셈이네. 조금 설렜으려나.","JPN":"ふふっ。それなりに使えると認められたってことね。少し照れちゃうわ。","ENG":"Haha. Just means that he found a use for me. That's a little exciting.","TWN":"呵呵，這就表示他認同我的意思吧？有點開心呢。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"보모 역할로 인정받은 것 아닌가요? 메이드는 아니신 것 같은데요.","JPN":"保母として認められたんですよね？　メイドではないと思いますが。","ENG":"Has he found use for you as a nanny? Because I don't think you're fit to be a maid.","TWN":"是指保母的部分吧？畢竟你應該不是女僕吧？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"보모가 어때서?","JPN":"保母だから何？","ENG":"What's so bad about being a nanny?","TWN":"保母又怎麼樣？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"누군가에게 자기 가치를 인정받는다는 건 행복한 경험이야. 그렇게 생각 안 하니?","JPN":"誰かに自分の価値を認められるというのは幸せなことよ。そう思わない？","ENG":"Having your worth valued by someone else is a happy experience. Don't you think so?","TWN":"你不認為有人認同你的價值是件很幸福的事嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저는……","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저는 제 평가를 위해 일하지 않습니다. 메이드로서 소임을 다할 뿐이죠.","JPN":"私は自分の評価のために働いていません。メイドとしての仕事を全うするだけです。","ENG":"I don't work to be evaluated. I merely do my best as a maid.","TWN":"我做事不是因為要得到認可，我只是盡女僕的義務而已。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"베로니카 씨처럼 말이지?","JPN":"ベロニカさんのように、でしょ？","ENG":"Like Veronica, right?","TWN":"你是說像貝洛妮卡那樣嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……메이드장 님을 알고 계셨나요? 구구절절 설명할 필요가 없었네요.","JPN":"……メイド長をご存じでしたか。いちいち説明する必要はありませんでしたね。","ENG":"...You know Chief Maid? Then I didn't need to explain in detail.","TWN":"……你也認識女僕長？那就不用拐彎抹角了。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 분은 완전 쩌십니다. 메이드장 님이 계신 한…….","JPN":"あの方はまじでえぐいです。メイド長がいらっしゃる限り……","ENG":"She's totally rad. As long as she is with us–","TWN":"女僕長超強的，只要有她在……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"응? 무슨 소리지?","JPN":"うん？　なんの音かしら？","ENG":"Hmm? What's that sound?","TWN":"嗯？什麼聲音？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저 상어가 원인입니다. 수족관 안을 보세요.","JPN":"あのサメが原因です。辺りを見てください。","ENG":"That shark seems to be the cause. Look inside the aquarium.","TWN":"是那隻鯊魚，你看水族箱裡面。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_A","text":{"KOREA":"저 상어 왠지 이상해. 갑자기 계속 유리에 들이받고 있어.","JPN":"あのサメ、どこかおかしいぞ。ずっとガラスに体当たりしている。","ENG":"That shark is acting strangely. It suddenly started ramming into the glass wall.","TWN":"那隻鯊魚好像怪怪的，突然一直撞玻璃。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_B","text":{"KOREA":"사람 불러야 하는 거 아냐? 저러다 다치면 어떡해?","JPN":"職員を呼んだ方がいいんじゃないか？　怪我人でもでたらどうするんだ！","ENG":"Don't we need to tell the staff? What if someone gets hurt?","TWN":"要叫工作人員過來嗎？萬一受傷的話怎麼辦？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"흐음…… 입에 물고 있는 저거, 보물 상자 맞지?","JPN":"ふむ……口に加えているあれ、宝箱よね？","ENG":"Hmm... What's it got in its mouth? That's a treasure chest, right?","TWN":"嗯……牠嘴裡咬著的是藏寶箱對吧？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네. 제 눈에도 그렇게 보이는군요.","JPN":"はい。私にもそう見えます。","ENG":"Yes. I would say that is.","TWN":"是，我看到的也是這樣。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 보물 상자 맞아!","JPN":"うん！　宝箱だよ！","ENG":"Yup! It's a treasure chest!","TWN":"沒錯！就是藏寶箱！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"내가 상어한테 가져와 달라고 부탁했어!","JPN":"私がサメさんに持ってきてってお願いしたの！","ENG":"I asked the shark to bring it over to me!","TWN":"是我拜託鯊魚拿來給我的！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L50_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저러다 유리벽이 깨지겠어요.","JPN":"このままでは水槽が割れてしまいます。","ENG":"It's going to shatter the glass wall at this rate.","TWN":"再這樣下去玻璃牆會撞破的。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"즉효성 수면제가 있습니다. 하지만 물 속에 있는 동물에게는……","JPN":"私が即効性の睡眠剤を持っています。しかし水中の動物には……","ENG":"I have an instant tranquilizer, but I don't think it will work for animals underwater...","TWN":"我是有安眠藥，但是我怕水裡的其他動物……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"아니. 그것보다 더 쉬운 방법이 있어.","JPN":"いいえ。それよりもっと簡単な方法があるわ。","ENG":"No, there's an easier way.","TWN":"不用，我有更簡單的方法。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"알렉스 님, 가까이 다가가지 마세요. 위험합니다.","JPN":"アレックス様、それ以上近づいてはいけません。危険です。","ENG":"Ms. Alex, please don't get too close. It is dangerous.","TWN":"雅蕾克絲小姐，不要靠太近，危險。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗, 걱정해 주는 거니?","JPN":"ふふっ、心配してくれているのかしら？","ENG":"Haha. Are you worried about me?","TWN":"呵呵，你在替我擔心嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"괜찮아. 이렇게 유리벽을 살짝 두드려 주면.","JPN":"大丈夫よ。こういう感じでガラスを軽く叩いてあげれば。","ENG":"It's okay. If I just lightly tap on the glass...","TWN":"放心，只要輕輕敲玻璃，"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"……얌전해지거든.","JPN":"……大人しくなるわ。","ENG":"...it'll calm down.","TWN":"……牠就會安靜下來。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗, 상어가 가 버렸어…….","JPN":"あっ、サメさんが行っちゃった……","ENG":"Oh, the shark went away...","TWN":"啊，鯊魚游走了……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"알렉스 님……. 카운터셨군요.","JPN":"アレックス様……カウンターだったんですね。","ENG":"Ms. Alex... You are a Counter.","TWN":"雅蕾克絲小姐……原來你是制裁者。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"하지만 방금까지 날뛰던 상어를 얌전하게 만들다니, 정신 조종계 능력인가요?","JPN":"しかしあの暴れていたサメを瞬時に大人しくさせるなんて、マインドコントロール系の能力ですか？","ENG":"You just made a rampaging shark become docile. Is it mental control?","TWN":"你竟然可以讓暴躁的鯊魚安靜下來，你的能力是可以控制意念嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"파동을 제어하는 능력이야. 수준은 변변치 않지만.","JPN":"波動を制御する能力よ。大したレベルじゃないけどね。","ENG":"My ability is controlling waves. It's fairly weak, though.","TWN":"是可以控制波動的能力，不過沒有很厲害啦。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"파동이요? 그런데 어떻게 상어를……?","JPN":"波動？　それでどうやってサメを……？","ENG":"Waves? Then how did you do that thing with the shark...?","TWN":"波動嗎？那鯊魚為什麼會……？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"상어는 물 속에서 자기장이나 진동을 잘 감지하거든.","JPN":"サメは水中で磁場や振動を感知する能力に長けているの。","ENG":"Sharks are sensitive to vibrations and magnetic fields underwater.","TWN":"鯊魚對於水中的磁場或是震動很敏感。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그걸 이용해서 살짝 놀라게 했는데…… 수족관에 살던 아이에겐 조금 심했으려나.","JPN":"それを利用して軽く驚かせたんだけど……水族館暮らしの子相手に少しやりすぎたかしらね。","ENG":"I just startled it using that, but... maybe it was a big shock to one that lives in an aquarium.","TWN":"我本來是想利用這一點稍微嚇嚇牠……但對於只在水族館生活過的牠而言，可能有點超過。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오! 굉장하다, 언니!","JPN":"おお！　すごいね、お姉ちゃん！","ENG":"Ooh! That's amazing, Alex!","TWN":"哇喔！姊姊好厲害！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"쉽게 믿기지가 않네요. 그렇게 정밀한 사용이 가능한 건가요?","JPN":"にわかには信じがたいですね。そのような精密なコントロールができるんですか？","ENG":"It is hard to believe. How can you use it so precisely?","TWN":"真不敢相信，可以控制得如此細膩嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그러게. 애들 지키려다 보니 어떻게든 방법을 찾게 되더라.","JPN":"そうね。子どもたちを守ろうと頑張っていたら、徐々にやり方がわかってきたって感じかしらね。","ENG":"I dunno. I somehow found a way while trying to protect the kids.","TWN":"那當然，要保護孩子們就一定要想盡辦法。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그리고 시그마. 네 부탁을 들어주느라 상어가 크게 다칠 뻔했어.","JPN":"あとシグマちゃん。あなたのお願いを聞くためにサメが大けがをするところだったのよ。","ENG":"And Sigma, the shark was almost injured while listening to your request.","TWN":"西格瑪，鯊魚因為你的拜託差點受傷，"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"미안하다고 사과해야지?","JPN":"ごめんなさいって謝らないとね？","ENG":"You should go apologize to it, right?","TWN":"你是不是應該跟牠道歉呢？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으응…….","JPN":"ううん……","ENG":"Okay...","TWN":"嗯嗯……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"미안해, 상어야! 다음엔 우리 같이 물속에서 재밌게 놀자!","JPN":"ごめんねさい、サメさん！　今度は一緒に水の中で楽しく遊ぼう！","ENG":"I'm sorry, shark! Let's play in the water together next time!","TWN":"鯊魚對不起！下次我們一起在水裡玩！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_A","text":{"KOREA":"저, 저기요! 저 아이예요! 쟤가 상어를 조종한다고 했어요!","JPN":"あ、あの！　あの子です！　あの子がサメを操っていると言っていましたよ！","ENG":"O-over here! It's her! She said that she controlled the shark!","TWN":"就是她！就是那個小女孩！她說她可以控制鯊魚！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_B","text":{"KOREA":"테러하러 온 카운터 범죄자일지도 모르잖아요! 어서 조사해 봐요!","JPN":"テロ目的のカウンター犯罪者かもしれません！　早く調査してください！","ENG":"They might be criminal Counters here to cause terrorism! Go investigate them!","TWN":"誰知道她是不是制裁者罪犯！趕快把她抓起來調查！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"거기 세 분! 잠시 협조 부탁드립니다!","JPN":"そこの三人！　少しご同行願えますか！","ENG":"You three! Could you come with us?","TWN":"三位小姐！請你們協助調查！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저희를 제압하러 온 모양이군요. 대응할까요?","JPN":"私たちを制圧しに来たようですね。相手をしますか？","ENG":"I think the guard's here to arrest us. Should I respond?","TWN":"似乎是來逮捕我們的？要反抗嗎？"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"괜히 소란 피우면 네 주인님 체면에 먹칠을 하게 될 텐데?","JPN":"余計な騒ぎを起こせば、あなたのご主人様の顔に泥を塗ることになるわよ？","ENG":"If you cause a ruckus for no reason, you'll be ruining your master's reputation.","TWN":"要是把事情鬧大，會害你的主人顏面掃地的。"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"시그마, 우리 누가 먼저 공원까지 가나 시합할래?","JPN":"シグマちゃん、どっちが先に公園に着くか競争する？","ENG":"Sigma, wanna race to see who can reach the park first?","TWN":"西格瑪，我們來比賽，看誰先跑到公園！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"시합? 응! 할래, 할래!","JPN":"競争！　うん！　やる、やる！","ENG":"A race? Yeah! Let's do it!","TWN":"比賽？好！我們來比賽！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"좋아, 그럼 준비……","JPN":"よし、それじゃあ、よ～い……","ENG":"Okay. Then, ready, set...","TWN":"好喔，預備……"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"시─작!","JPN":"どーん！","ENG":"GO!","TWN":"開─始！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"와아아!","JPN":"わああ！","ENG":"Yay!","TWN":"哇～～！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"상어야, 아프지 말고 잘 있어! 또 올게!","JPN":"サメさん、元気でね！　また来るから！","ENG":"Bye, shark! Don't get sick and stay safe! I'll come back later!","TWN":"鯊魚你要好好照顧自己，我會再來找你玩喔！"},"stage":{"bg":"AQUARIUM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……모처럼 따님을 모시게 되었는데 엉망이 됐어요.","JPN":"……せっかくお嬢様の世話係を任されたのに、めちゃくちゃです。","ENG":"...It was my day to watch over Sigma but it is all ruined.","TWN":"……難得有機會伺候小姐，結果卻搞砸了。"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"수족관 관람 이후에 다른 일정들이 기다리고 있었는데…….","JPN":"水族館の後も計画があったのですが……","ENG":"I planned to do other things after going to the aquarium...","TWN":"原本水族館後面還有行程說……"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"시그마, 여기 호수에 사는 물고기는 뭘까?","JPN":"シグマちゃん、この湖にいる魚はどんな魚かしら？","ENG":"Sigma, what kind of fish do you think live in this lake?","TWN":"西格瑪，你知道這湖裡的是什麼魚嗎？"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"<color=#ffd34c>잉어과</color>의 <color=#ffd34c>비단잉어</color>야!","JPN":"<color=#ffd34c>鯉科</color>の<color=#ffd34c>錦鯉</color>だよ！","ENG":"<color=#ffd34c>Koi</color> from the <color=#ffd34c>carp family</color>!","TWN":"是屬<color=#ffd34c>鯉科</color>的<color=#ffd34c>錦鯉</color>！"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 정답이야. 완벽해.","JPN":"ふふっ、正解。完璧ね。","ENG":"Haha. That's correct. Perfect.","TWN":"呵呵，答對囉，好棒喔！"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"배고파 보이는데 밥을 줘 볼까?","JPN":"お腹が空いているように見えるわね、餌をあげてみようか？","ENG":"They look hungry. Do you want to feed them?","TWN":"你是不是肚子餓啦？我拿點東西給你吃好嗎？"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"여기 간식으로 싸 왔던 샌드위치야. 이렇게 귀퉁이를 조금 떼어 주면……","JPN":"これ、おやつにと思って持ってきたサンドイッチよ。こうやって耳を少しちぎって投げるれば……","ENG":"Here's the sandwich we brought to eat as a snack. If we take a little bit off from the corner, and...","TWN":"這是我買來當零食的三明治，像這樣撕開角角……"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오! 진짜 많다!","JPN":"わあ！　本当にたくさんいる！","ENG":"Ooh! So many fish!","TWN":"哇喔！好多喔！"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래도…… 따님께서 기뻐하시는 것 같으니 괜찮지만요.","JPN":"でも……お嬢様が喜んでくれているようなので、良しとします。","ENG":"But... since Sigma seems happy, I think it's all right.","TWN":"不過……小姐開心就好。"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……저도 아직 메이드로서 가야 할 길이 머네요.","JPN":"……私もメイドとしてはまだまだのようです。","ENG":"...I still seem to have a long way to go as a maid.","TWN":"……看來我的女僕之路還很遙遠。"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};